using System.ClientModel;
using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT");

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI (or compatible) API key.");

var topic = args.Length > 0
    ? string.Join(' ', args)
    : "the impact of large language models on software engineering in 2025";

Console.WriteLine($"🔍 Research Agent — topic: \"{topic}\"\n");

// --- Build the chat client with tool support ---
var clientOptions = new OpenAIClientOptions();
if (endpoint is not null)
    clientOptions.Endpoint = new Uri(endpoint);

IChatClient client = new OpenAIClient(new ApiKeyCredential(apiKey), clientOptions)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// --- Tools ---
var notebook = new Notebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        (string query) => WebSearch.SearchAsync(query),
        "web_search",
        "Searches the web for the given query and returns a list of result snippets."),

    AIFunctionFactory.Create(
        ([Description("Short label for the note")] string title,
         [Description("Content to save")] string content) =>
        {
            notebook.Save(title, content);
            return $"Note \"{title}\" saved.";
        },
        "save_note",
        "Saves a research note for later reference."),

    AIFunctionFactory.Create(
        () => notebook.GetAllNotes(),
        "get_notes",
        "Returns all previously saved research notes."),
};

// --- Agent loop ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given topic by:
        1. Searching the web multiple times with varied queries to gather diverse information.
        2. Saving key findings as notes using the save_note tool.
        3. After gathering enough information, retrieving your notes and producing a
           well-structured summary with sections and references.
        Be thorough — perform at least 3 different searches before summarizing.
        """),
    new(ChatRole.User, $"Please research this topic and provide a summary: {topic}"),
};

var options = new ChatOptions { Tools = [.. tools] };

const int maxIterations = 15;
for (var i = 0; i < maxIterations; i++)
{
    var response = await client.GetResponseAsync(messages, options);

    // Append every response message to the conversation history.
    messages.AddRange(response.Messages);

    // If the model finished without requesting any tool calls, we're done.
    if (response.FinishReason == ChatFinishReason.Stop)
    {
        Console.WriteLine("\n===== RESEARCH SUMMARY =====\n");
        var finalText = response.Messages
            .Where(m => m.Role == ChatRole.Assistant)
            .SelectMany(m => m.Contents.OfType<TextContent>())
            .LastOrDefault()?.Text;
        Console.WriteLine(finalText ?? "(no summary produced)");
        break;
    }
}

Console.WriteLine("\n📒 Notebook contents:");
foreach (var (title, content) in notebook.Notes)
    Console.WriteLine($"  • {title}: {content[..Math.Min(content.Length, 120)]}...");

// ============================================================
// Supporting types
// ============================================================

/// <summary>Simple in-memory notebook for the agent's research notes.</summary>
sealed class Notebook
{
    public List<(string Title, string Content)> Notes { get; } = [];

    public void Save(string title, string content)
    {
        Notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: {title}");
    }

    public string GetAllNotes() =>
        Notes.Count == 0
            ? "No notes saved yet."
            : string.Join("\n\n", Notes.Select((n, i) => $"[{i + 1}] {n.Title}\n{n.Content}"));
}

/// <summary>Web search tool that uses the Bing search API when available, otherwise returns
/// a simulated result so the agent loop can still be demonstrated.</summary>
static class WebSearch
{
    private static readonly HttpClient Http = new();

    public static async Task<string> SearchAsync(string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        // If a Bing API key is available, perform a real search.
        var bingKey = Environment.GetEnvironmentVariable("BING_API_KEY");
        if (!string.IsNullOrEmpty(bingKey))
        {
            try
            {
                var url = $"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count=5";
                var request = new HttpRequestMessage(HttpMethod.Get, url);
                request.Headers.Add("Ocp-Apim-Subscription-Key", bingKey);
                var response = await Http.SendAsync(request);
                response.EnsureSuccessStatusCode();
                return await response.Content.ReadAsStringAsync();
            }
            catch (Exception ex)
            {
                return $"Search failed ({ex.Message}). Falling back to simulated results.";
            }
        }

        // Simulated results so the demo works without an API key.
        await Task.Delay(250); // simulate latency
        return $"""
            Search results for "{query}":
            1. "{query}" — Wikipedia overview covering history, key developments, and current state.
               Snippet: This topic has seen significant growth and attention from both academia and industry.
            2. "Recent advances in {query}" — Academic survey (2025)
               Snippet: A comprehensive survey highlighting breakthroughs, open challenges, and future directions.
            3. "{query}: Industry perspectives" — TechCrunch article
               Snippet: Leading companies are investing heavily, with practical applications emerging across sectors.
            4. "The future of {query}" — Research blog
               Snippet: Experts predict transformative changes in the next 3-5 years driven by ongoing innovation.
            5. "{query} ethical considerations" — Journal of AI Ethics
               Snippet: Growing consensus on the need for responsible development practices and governance frameworks.
            """;
    }
}

